import {
  CheckCircleIcon,
  ExclamationTriangleIcon,
  InformationCircleIcon,
  XCircleIcon,
  XMarkIcon,
} from "@heroicons/react/24/solid";

const variantStyles = {
  success: {
    title: "Success",
    icon: CheckCircleIcon,
    accent: "bg-emerald-500",
    ring: "ring-emerald-100",
    text: "text-emerald-950",
    message: "text-emerald-900/80",
  },
  error: {
    title: "Error",
    icon: XCircleIcon,
    accent: "bg-rose-500",
    ring: "ring-rose-100",
    text: "text-rose-950",
    message: "text-rose-900/80",
  },
  info: {
    title: "Update",
    icon: InformationCircleIcon,
    accent: "bg-sky-500",
    ring: "ring-sky-100",
    text: "text-slate-950",
    message: "text-slate-700",
  },
  default: {
    title: "Notice",
    icon: ExclamationTriangleIcon,
    accent: "bg-amber-500",
    ring: "ring-amber-100",
    text: "text-amber-950",
    message: "text-amber-900/80",
  },
};

export default function NotificationTemplate({
  message,
  options,
  style,
  close,
}) {
  const variant = variantStyles[options.type] || variantStyles.default;
  const Icon = variant.icon;

  return (
    <div
      role="alert"
      style={style}
      className={`shopsphere-alert ${variant.ring} bg-white/95 ${variant.text}`}
    >
      <div className={`shopsphere-alert__accent ${variant.accent}`} />
      <div className="shopsphere-alert__icon">
        <Icon className="h-5 w-5" />
      </div>
      <div className="min-w-0 flex-1">
        <p className="shopsphere-alert__title">{variant.title}</p>
        <p className={`shopsphere-alert__message ${variant.message}`}>
          {message}
        </p>
      </div>
      <button
        type="button"
        onClick={close}
        aria-label="Dismiss notification"
        className="shopsphere-alert__close"
      >
        <XMarkIcon className="h-4 w-4" />
      </button>
    </div>
  );
}
